using System;
using System.Collections.Generic;
using System.Globalization;
using System.IO;

namespace ProjectorDash
{
    /// <summary>
    /// Compact offline airport catalog. Coordinates are derived from the
    /// public-domain OurAirports data set; only airports with scheduled
    /// service and an IATA code are kept. No lookup runs over the network.
    /// </summary>
    internal static class AirportCatalog
    {
        private const double EarthRadiusKm = 6371.0;
        private const double Degrees = Math.PI / 180.0;
        private static readonly object Sync = new object();
        private static List<AirportEntry> _entries;
        private static double _cachedLatitude = double.NaN;
        private static double _cachedLongitude = double.NaN;
        private static List<AirportReading> _cachedNearby;

        private sealed class AirportEntry
        {
            public string Code;
            public double Latitude;
            public double Longitude;
        }

        public static List<AirportReading> FindNearby(double latitude,
            double longitude)
        {
            lock (Sync)
            {
                if (_cachedNearby != null &&
                    Math.Abs(latitude - _cachedLatitude) < 0.000001 &&
                    Math.Abs(longitude - _cachedLongitude) < 0.000001)
                    return Clone(_cachedNearby);

                List<AirportReading> result = new List<AirportReading>();
                foreach (AirportEntry airport in Entries())
                {
                    double distance = HaversineKm(latitude, longitude,
                        airport.Latitude, airport.Longitude);
                    if (distance > 250.0) continue;
                    result.Add(new AirportReading
                    {
                        Code = airport.Code,
                        DistanceKm = distance,
                        BearingDegrees = InitialBearing(latitude, longitude,
                            airport.Latitude, airport.Longitude)
                    });
                }
                result.Sort(delegate(AirportReading a, AirportReading b)
                {
                    return a.DistanceKm.CompareTo(b.DistanceKm);
                });
                if (result.Count > 5) result.RemoveRange(5, result.Count - 5);
                _cachedLatitude = latitude;
                _cachedLongitude = longitude;
                _cachedNearby = Clone(result);
                return result;
            }
        }

        private static List<AirportReading> Clone(List<AirportReading> source)
        {
            List<AirportReading> result = new List<AirportReading>();
            foreach (AirportReading airport in source)
            {
                result.Add(new AirportReading
                {
                    Code = airport.Code,
                    DistanceKm = airport.DistanceKm,
                    BearingDegrees = airport.BearingDegrees
                });
            }
            return result;
        }

        private static List<AirportEntry> Entries()
        {
            if (_entries != null) return _entries;
            List<AirportEntry> result = new List<AirportEntry>();
            using (StringReader reader = new StringReader(AirportData))
            {
                string line;
                while ((line = reader.ReadLine()) != null)
                {
                    string[] parts = line.Split('|');
                    double latitude;
                    double longitude;
                    if (parts.Length != 3 ||
                        !double.TryParse(parts[1], NumberStyles.Float,
                            CultureInfo.InvariantCulture, out latitude) ||
                        !double.TryParse(parts[2], NumberStyles.Float,
                            CultureInfo.InvariantCulture, out longitude))
                        continue;
                    result.Add(new AirportEntry
                    {
                        Code = parts[0],
                        Latitude = latitude,
                        Longitude = longitude
                    });
                }
            }
            _entries = result;
            return _entries;
        }

        private static double HaversineKm(double lat1, double lon1,
            double lat2, double lon2)
        {
            double dLat = (lat2 - lat1) * Degrees;
            double dLon = (lon2 - lon1) * Degrees;
            double a = Math.Sin(dLat / 2.0) * Math.Sin(dLat / 2.0) +
                Math.Cos(lat1 * Degrees) * Math.Cos(lat2 * Degrees) *
                Math.Sin(dLon / 2.0) * Math.Sin(dLon / 2.0);
            return EarthRadiusKm * 2.0 *
                Math.Atan2(Math.Sqrt(a), Math.Sqrt(Math.Max(0.0, 1.0 - a)));
        }

        private static double InitialBearing(double lat1, double lon1,
            double lat2, double lon2)
        {
            double first = lat1 * Degrees;
            double second = lat2 * Degrees;
            double deltaLongitude = (lon2 - lon1) * Degrees;
            double y = Math.Sin(deltaLongitude) * Math.Cos(second);
            double x = Math.Cos(first) * Math.Sin(second) -
                Math.Sin(first) * Math.Cos(second) * Math.Cos(deltaLongitude);
            double bearing = Math.Atan2(y, x) / Degrees % 360.0;
            return bearing < 0.0 ? bearing + 360.0 : bearing;
        }

